use criterion::{black_box, criterion_group, criterion_main, Criterion};
use ndarray::{Array1, Array2};
use stats_models::{Lasso, Ridge};
use resample::{bootstrap, BootstrapConfig, BootstrapStatistic};

#[derive(Clone, Copy)]
struct SimpleStatistic;

impl BootstrapStatistic for SimpleStatistic {
    fn compute(&self, _x: ndarray::ArrayView2<f64>, y: ndarray::ArrayView1<f64>) -> Array1<f64> {
        Array1::from(vec![y.mean().unwrap_or(0.0)])
    }

    fn n_stats(&self) -> usize {
        1
    }
}

fn benchmark_lasso_performance(c: &mut Criterion) {
    let n_obs = 100;
    let n_vars = 3;

    // Generate test data
    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    let mut y_data = Vec::with_capacity(n_obs);

    for i in 0..n_obs {
        x_data.push(1.0); // intercept
        x_data.push(i as f64); // x1
        x_data.push((i as f64) * 0.5); // x2

        // y = 2 + 1.5*x1 + 0.5*x2 + noise
        y_data.push(2.0 + 1.5 * (i as f64) + 0.5 * (i as f64 * 0.5) + 0.1 * (i as f64).sin());
    }

    let x_matrix = Array2::from_shape_vec((n_obs, n_vars), x_data).unwrap();
    let y_vector = Array1::from(y_data);

    c.bench_function("lasso_fit", |b| {
        b.iter(|| {
            let _result = Lasso::fit(
                black_box(x_matrix.view()),
                black_box(y_vector.view()),
                black_box(0.1),
                None,
            );
        })
    });
}

fn benchmark_ridge_performance(c: &mut Criterion) {
    let n_obs = 100;
    let n_vars = 3;

    // Generate test data
    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    let mut y_data = Vec::with_capacity(n_obs);

    for i in 0..n_obs {
        x_data.push(1.0); // intercept
        x_data.push(i as f64); // x1
        x_data.push((i as f64) * 0.5); // x2

        // y = 2 + 1.5*x1 + 0.5*x2 + noise
        y_data.push(2.0 + 1.5 * (i as f64) + 0.5 * (i as f64 * 0.5) + 0.1 * (i as f64).sin());
    }

    let x_matrix = Array2::from_shape_vec((n_obs, n_vars), x_data).unwrap();
    let y_vector = Array1::from(y_data);

    c.bench_function("ridge_fit", |b| {
        b.iter(|| {
            let _result = Ridge::fit(
                black_box(x_matrix.view()),
                black_box(y_vector.view()),
                black_box(0.1),
                None,
            );
        })
    });
}

fn benchmark_bootstrap_performance(c: &mut Criterion) {
    let n_obs = 50;
    let n_vars = 3;

    // Generate test data
    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    let mut y_data = Vec::with_capacity(n_obs);

    for i in 0..n_obs {
        x_data.push(1.0); // intercept
        x_data.push(i as f64); // x1
        x_data.push((i as f64) * 0.5); // x2

        // y = 2 + 1.5*x1 + 0.5*x2 + noise
        y_data.push(2.0 + 1.5 * (i as f64) + 0.5 * (i as f64 * 0.5) + 0.1 * (i as f64).sin());
    }

    let x_matrix = Array2::from_shape_vec((n_obs, n_vars), x_data).unwrap();
    let y_vector = Array1::from(y_data);

    let stat = SimpleStatistic;
    let config = BootstrapConfig {
        n_samples: 100,
        seed: Some(42),
        parallel: true,
    };

    c.bench_function("bootstrap_lasso_parallel", |b| {
        b.iter(|| {
            let _result = bootstrap(
                black_box(x_matrix.view()),
                black_box(y_vector.view()),
                black_box(stat),
                black_box(Some(config.clone())),
            );
        })
    });
}

criterion_group!(
    benches,
    benchmark_lasso_performance,
    benchmark_ridge_performance,
    benchmark_bootstrap_performance
);
criterion_main!(benches);

