        let y_mean: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| fitted + resid)
            .sum::<f64>()
            / n;

        let tss: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| {
                let y = fitted + resid;
                (y - y_mean).powi(2)
            })
            .sum();

        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
