use ndarray::{Array1, Array2};
use stats_models::{glm, Gaussian, Lasso, Ridge};

fn main() {
    // Create some test data
    let n = 100;
    let p = 5;

    // Create design matrix with intercept
    let mut x_data = Vec::with_capacity(n * p);
    for i in 0..n {
        x_data.push(1.0); // intercept
        for j in 1..p {
            x_data.push((i as f64) * 0.1 + (j as f64) * 0.2);
        }
    }
    let x = Array2::from_shape_vec((n, p), x_data).unwrap();

    // Create response
    let y: Array1<f64> = Array1::from_vec(
        (0..n).map(|i| 2.0 + 3.0 * (i as f64) * 0.1).collect()
    );

    // Test 1: Standard GLM (no regularization)
    println!("Testing standard GLM (no regularization)...");
    let _fit1 = stats_models::Glm::fit_ndarray(x.view(), y.view(), Gaussian, None, None).unwrap();
    println!("✓ Standard GLM works");

    // Test 2: Lasso regression
    println!("\nTesting Lasso regression (alpha=1.0, lambda=0.1)...");
    let fit2 = Lasso::fit(x.view(), y.view(), 0.1, None).unwrap();
    println!("✓ Lasso works");
    println!("  Coefficients: {:?}", &fit2.coefficients()[..3]);

    // Test 3: Ridge regression
    println!("\nTesting Ridge regression (alpha=0.0, lambda=0.5)...");
