impl RegularizedFit {
    /// Create a RegularizedFit from coordinate descent results
    pub fn from_coordinate_descent(
        result: optimcore::OptimResult,
        x_matrix: ndarray::Array2<f64>,
        y_vector: ndarray::Array1<f64>,
        lambda: f64,
        alpha: f64,
    ) -> Self {
        let n_obs = x_matrix.nrows();

        // Calculate fitted values
        let fitted_values: Vec<f64> = (0..n_obs)
            .map(|i| {
                x_matrix.row(i).iter()
                    .zip(&result.params)
