// ... inside coordinate_descent_with_start ...
    let mut active_set: Vec<usize> = (0..n_vars).collect();
    let mut all_features: Vec<usize> = (0..n_vars).collect();

    for iteration in 0..config.max_iter {
        let features_to_update = if iteration % 10 == 0 {
            // Periodically check all features for KKT violations
            &all_features
        } else {
            &active_set
        };

        for &j in features_to_update {
            // ... existing coordinate update logic for feature j ...
            let delta = new_beta_j - beta[j];
            if delta.abs() > 1e-10 {
                // Update residuals
                residuals.scaled_add(-delta, &x.column(j)); // In-place update
                beta[j] = new_beta_j;
            }
        }

        // After a full pass, rebuild the active set
        if iteration % 10 == 0 {
            active_set = (0..n_vars)
                .filter(|&j| beta[j] != 0.0)
                .collect();
        }

        // ... convergence check ...
    }
// ...
```
